// generar_212_tests_por_especie.js
// CHIQUI Entre Señales — Tests rápidos filtrados por especie
//
// Qué corrige:
// Los tests rápidos aparecían TODOS para todas las mascotas. La causa:
// la página de Prevención nunca le pasaba la especie de la mascota al
// componente ExamenesLab (la prop existía pero no se enviaba), así que
// el filtro por especie no tenía con qué filtrar.
//
// 1) app/prevencion/page.tsx → ahora pasa especie={mascota.especie}.
//    Esto también arregla los rangos por defecto de densidad urinaria
//    (USG) del examen de orina, que dependen de la especie y tampoco
//    se estaban aplicando por lo mismo.
// 2) components/ExamenesLab.tsx → el filtro es estricto: gatos ven
//    SOLO tests felinos, perros SOLO tests caninos. Si una especie no
//    tiene tests en el catálogo, no se muestra ninguno predefinido y
//    queda "+ agregar otro test" para escribirlo a mano.
//
// No hay SQL.
//
// Uso: arrastrar este archivo a la raíz del proyecto y correr:
//   node generar_212_tests_por_especie.js

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: "components/ExamenesLab.tsx",
    base64: ""
  },
  {
    ruta: "app/prevencion/page.tsx",
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs2.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('')
  console.log('Listo. 2 archivos escritos correctamente.')
  console.log('No hay SQL esta vez. Puedes hacer git add / commit / push directo.')
} else {
  console.error('')
  console.error('Terminó con ' + errores + ' error(es). NO hagas git push todavía.')
  process.exit(1)
}
